# Colored shapes that extend shapes module

from shapes import Shape, Rectangle, Circle

class ColoredShape:
    color: str

    def __init__(self, color: str):
        self.color = color

    def get_color(self) -> str:
        return self.color

class ColoredRectangle(Rectangle, ColoredShape):
    def __init__(self, width: float, height: float, color: str):
        # Initialize parent Rectangle
        super().__init__(width, height)
        # Initialize ColoredShape
        self.color = color

class ColoredCircle(Circle, ColoredShape):
    def __init__(self, radius: float, color: str):
        # Initialize parent Circle
        super().__init__(radius)
        # Initialize ColoredShape
        self.color = color

def create_colored_shape(shape_type: str, size: float, color: str) -> ColoredShape:
    if shape_type == "rect":
        return ColoredRectangle(size, size * 0.5, color)
    else:
        return ColoredCircle(size, color)
